#!/bin/bash
# Remove all files generated by 00_, 01_, and 02_ scripts

set -euo pipefail

read -r -p "This will delete data/, results/, benchmark5.5/, complexes.txt, and the archive. Continue? [y/N] " confirm
[[ "$confirm" == [yY] ]] || {
  echo "Aborted."
  exit 0
}

echo "Cleaning up generated files..."

rm -rf benchmark5.5.tgz benchmark5.5/ data/ results/ complexes.txt

echo "Done."
